@@ -50,6 +50,18 @@ namespace Catch {
     {}

     bool TestSpec::TagPattern::matches( TestCaseInfo const& testCase ) const {
+        if ( m_tag.find( '*' ) != std::string::npos ) {
+            // Wildcard tag pattern — check each tag against the pattern
+            WildcardPattern wildcard( m_tag, CaseSensitive::No );
+            return std::any_of(
+                begin( testCase.tags ),
+                end( testCase.tags ),
+                [&wildcard]( Tag const& tag ) {
+                    return wildcard.matches(
+                        std::string( tag.original.data(),
+                                     tag.original.size() ) );
+                } );
+        }
         return std::find( begin( testCase.tags ),
                           end( testCase.tags ),
                           Tag( m_tag ) ) != end( testCase.tags );
